/* ══ MODAL LOGIC — openPModal, closePModal, openBModal, closeBModal ══ */

/* ══ PRODUCT MODAL — IMAGE NAV STATE ══ */
        let pmCurrentImgs = null;
        let pmCurrentIdx = 0;

        function pmNavImage(dir) {
            if (!pmCurrentImgs || pmCurrentImgs.length < 2) return;
            pmCurrentIdx = (pmCurrentIdx + dir + pmCurrentImgs.length) % pmCurrentImgs.length;
            switchPackImg(pmCurrentImgs, pmCurrentIdx);
        }

/* ══ PRODUCT MODAL ══ */
        function openPModal(id) {
            const d = PRODUCTS[id];
            if (!d) return;
            document.getElementById('pm-glow').style.background = d.glow;
            document.getElementById('pm-brand').textContent = d.brand;

            const packInfo = PACK_COUNTS[id];
            const packImgs = (packInfo && PACK_IMAGES[packInfo.key]) ? PACK_IMAGES[packInfo.key] : null;

            const pmImg = document.getElementById('pm-img');
            pmImg.onerror = () => { if (d.img && pmImg.src.indexOf(d.img) === -1) pmImg.src = d.img; };
            pmImg.src = packImgs ? packImgs[0] : (d.img || '');
            pmImg.alt = d.name;
            pmImg.style.transform = 'scale(0.7) translateY(20px)';
            pmImg.style.opacity = '0';
            setTimeout(() => {
                pmImg.style.transition = 'transform .55s cubic-bezier(.34,1.56,.64,1), opacity .4s ease';
                pmImg.style.transform = 'scale(1) translateY(0)';
                pmImg.style.opacity = '1';
            }, 80);

            pmCurrentImgs = (packImgs && packImgs.length > 1) ? packImgs : null;
            pmCurrentIdx = 0;
            const prevBtn = document.getElementById('pm-prev');
            const nextBtn = document.getElementById('pm-next');
            if (prevBtn && nextBtn) {
                prevBtn.style.display = pmCurrentImgs ? '' : 'none';
                nextBtn.style.display = pmCurrentImgs ? '' : 'none';
            }

            const dotsEl = document.getElementById('pm-dots');
            dotsEl.innerHTML = '';
            if (packImgs && packImgs.length > 1) {
                packImgs.forEach((_, i) => {
                    const dot = document.createElement('div');
                    dot.className = 'pm-hero-dot' + (i===0?' active':'');
                    dot.onclick = () => switchPackImg(packImgs, i);
                    dotsEl.appendChild(dot);
                });
            }

            document.getElementById('pm-cat').textContent = d.cat;
            document.getElementById('pm-title').textContent = d.name;
            document.getElementById('pm-desc').textContent = d.desc;

            const specs = document.getElementById('pm-specs');
            specs.innerHTML = d.specs.map(s => `<div class="pm-spec"><div class="pm-spec-label">${s.l}</div><div class="pm-spec-val">${s.v}</div></div>`).join('');

            const flav = document.getElementById('pm-flavors');
            if (d.flavors && d.flavors.length) {
                document.getElementById('pm-flavor-tags').innerHTML = d.flavors.map(f => `<span class="pm-flavor-tag">${f}</span>`).join('') + '<span class="pm-flavor-tag pm-flavor-more">+ More</span>';
                flav.style.display = '';
            } else { flav.style.display = 'none'; }

            document.getElementById('pm-certs').innerHTML = d.certs.map(c => `<span class="pm-cert">✓ ${c}</span>`).join('');

            const galleryEl = document.getElementById('pm-gallery');
            const trackEl = document.getElementById('pm-gallery-track');
            if (packImgs && packImgs.length > 1) {
                trackEl.innerHTML = '';
                packImgs.forEach((src, i) => {
                    const thumb = document.createElement('div');
                    thumb.className = 'pm-gallery-thumb' + (i===0?' active':'');
                    const img = document.createElement('img');
                    img.alt = 'Pack ' + (i+1);
                    img.loading = 'lazy';
                    // لو الصورة مش موجودة/مكسورة، اخفي الـ thumbnail والـ dot بتاعها
                    img.onerror = () => {
                        thumb.style.display = 'none';
                        const dot = dotsEl.children[i];
                        if (dot) dot.style.display = 'none';
                    };
                    img.src = src;
                    thumb.appendChild(img);
                    thumb.onclick = () => switchPackImg(packImgs, i);
                    trackEl.appendChild(thumb);
                });
                galleryEl.style.display = '';
            } else { galleryEl.style.display = 'none'; }

            document.getElementById('pmodal').classList.add('open');
            document.body.style.overflow = 'hidden';
        }

        function switchPackImg(imgs, idx) {
            pmCurrentImgs = imgs;
            pmCurrentIdx = idx;
            const pmImg = document.getElementById('pm-img');
            pmImg.style.opacity = '0';
            pmImg.style.transform = 'scale(0.92)';
            setTimeout(() => {
                pmImg.src = imgs[idx];
                pmImg.style.transition = 'opacity .3s ease, transform .3s ease';
                pmImg.style.opacity = '1';
                pmImg.style.transform = 'scale(1)';
            }, 150);
            document.querySelectorAll('.pm-gallery-thumb').forEach((t,i) => t.classList.toggle('active', i===idx));
            document.querySelectorAll('.pm-hero-dot').forEach((dot,i) => dot.classList.toggle('active', i===idx));
        }

        function closePModal() {
            document.getElementById('pmodal').classList.remove('open');
            document.body.style.overflow = '';
        }

        /* ══ BRAND MODAL ══ */
        function openBModal(id) {
            const d = BRANDS[id];
            if (!d) return;
            // Brand modal icon — use real product image
            const bmIcon = document.getElementById('bm-icon');
            if (d.img) {
                bmIcon.innerHTML = '<img src="' + d.img + '" alt="' + d.name + '" style="width:80px;height:80px;object-fit:contain;filter:drop-shadow(0 6px 18px rgba(0,0,0,0.5));">';
            } else {
                bmIcon.textContent = d.icon || '';
            }
            document.getElementById('bm-name').textContent = d.name;
            document.getElementById('bm-type').textContent = d.type;
            document.getElementById('bm-desc').textContent = d.desc;
            document.getElementById('bm-product-list').innerHTML = d.products.map(p => {
                const pImg = {
                    'chillout-oat': 'images/chillout-oat-chips.webp',
                    'fire-fingers': 'images/fire-fingers.webp',
                    'oat-rings': 'images/oat-rings.webp',
                    'gourmet-popcorn': 'images/gourmet-popcorn.webp',
                    'lightpop-lolly': 'images/bozo-puffs-alt.webp',
                    'lightpop-premium': 'images/lightpop-logo.webp',
                    'lightpop-bonbon': 'images/lightpop-fruits-lollipop.webp',
                    'light-eclair': 'data:image/png;base64,',
                    'mojo-lolly': 'images/mojo-lolly.webp',
                    'honey-gum': 'images/honey-logo.webp',
                    'crazy-crisps': 'images/crazy-crisps-flaming-hot.webp',
                    'bozo-puffs': 'images/bozo-puffs.webp',
                    'tutti-lolly': 'images/tutti-lolly-2.webp'
                }[p.id] || '';
                return '<div class="bm-product-item" onclick="closeBModal();setTimeout(()=>openPModal(\'' + p.id + '\'),300)">' +
                    '<span class="bm-product-em">' +
                    (pImg ? '<img src="' + pImg + '" alt="' + p.name + '" style="width:44px;height:44px;object-fit:contain;filter:drop-shadow(0 3px 8px rgba(0,0,0,0.4));">' : p.em) +
                    '</span>' +
                    '<div><div class="bm-product-name">' + p.name + '</div><div class="bm-product-sub">' + p.sub + '</div></div>' +
                    '</div>';
            }).join('');
            document.getElementById('bmodal').classList.add('open');
            document.body.style.overflow = 'hidden';
        }

        function closeBModal() {
            document.getElementById('bmodal').classList.remove('open');
            document.body.style.overflow = '';
        }

        /* Close modals on backdrop click */
        document.getElementById('pmodal').addEventListener('click', e => {
            if (e.target === e.currentTarget) closePModal()
        });
        document.getElementById('bmodal').addEventListener('click', e => {
            if (e.target === e.currentTarget) closeBModal()
        });
        document.addEventListener('keydown', e => {
            if (e.key === 'Escape') {
                closePModal();
                closeBModal()
            }
            if (document.getElementById('pmodal').classList.contains('open')) {
                if (e.key === 'ArrowRight') pmNavImage(1);
                if (e.key === 'ArrowLeft') pmNavImage(-1);
            }
        });

        /* Swipe support على صورة المنتج (موبايل) */
        (function () {
            const hero = document.getElementById('pm-hero');
            if (!hero) return;
            let sx = 0, sy = 0, tracking = false;
            hero.addEventListener('touchstart', e => {
                if (e.touches.length !== 1) return;
                sx = e.touches[0].clientX;
                sy = e.touches[0].clientY;
                tracking = true;
            }, { passive: true });
            hero.addEventListener('touchend', e => {
                if (!tracking) return;
                tracking = false;
                const dx = e.changedTouches[0].clientX - sx;
                const dy = e.changedTouches[0].clientY - sy;
                if (Math.abs(dx) > 40 && Math.abs(dx) > Math.abs(dy)) {
                    pmNavImage(dx < 0 ? 1 : -1);
                }
            }, { passive: true });
        })();
